// Worker pool: fan-out work, fan-in results.
func workerPool(jobs <-chan int, results chan<- int, workers int) {
    var wg sync.WaitGroup
    for i := 0; i < workers; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for j := range jobs {        // ranges until jobs is closed AND drained
                results <- j * j
            }
        }()
    }
    go func() {
        wg.Wait()
        close(results)                   // close results only after all workers finish
    }()
}

// select multiplexes channel operations and honors cancellation.
func consume(ctx context.Context, results <-chan int) {
    for {
        select {
        case r, ok := <-results:
            if !ok {
                return                   // channel closed and drained
            }
            process(r)
        case <-ctx.Done():
            return                       // cancelled / deadline exceeded
        }
    }
}

// DATA RACE: concurrent unsynchronized writes to counter.
func racy() {
    counter := 0
    var wg sync.WaitGroup
    for i := 0; i < 1000; i++ {
        wg.Add(1)
        go func() { defer wg.Done(); counter++ }()  // counter++ is read-modify-write, not atomic
    }
    wg.Wait()
    fmt.Println(counter)   // almost never 1000; UB. go run -race flags this.
}

// FIXED with a mutex (clear, general):
func withMutex() int {
    var mu sync.Mutex
    counter := 0
    var wg sync.WaitGroup
    for i := 0; i < 1000; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            mu.Lock()
            counter++
            mu.Unlock()
        }()
    }
    wg.Wait()
    return counter   // exactly 1000
}

// FIXED with atomics (fastest for a single counter):
func withAtomic() int64 {
    var counter int64
    var wg sync.WaitGroup
    for i := 0; i < 1000; i++ {
        wg.Add(1)
        go func() { defer wg.Done(); atomic.AddInt64(&counter, 1) }()
    }
    wg.Wait()
    return atomic.LoadInt64(&counter)
}

func handleRequest(ctx context.Context) error {
    // Derive a child context with a 2s budget for downstream work.
    ctx, cancel := context.WithTimeout(ctx, 2*time.Second)
    defer cancel()                       // ALWAYS call cancel to free the timer goroutine

    data, err := fetchFromDB(ctx)        // db driver observes ctx.Done() and aborts
    if err != nil {
        return fmt.Errorf("fetch user: %w", err)   // %w wraps for errors.Is/As
    }
    _ = data
    return nil
}

var ErrNotFound = errors.New("not found")

func lookup() error {
    err := fmt.Errorf("lookup failed: %w", ErrNotFound)
    if errors.Is(err, ErrNotFound) {     // unwraps the chain to compare sentinels
        // handle the not-found case
    }
    var pathErr *os.PathError
    if errors.As(err, &pathErr) {        // extracts a concrete error type from the chain
        _ = pathErr.Path
    }
    return err
}

a := []int{1, 2, 3, 4, 5}
b := a[1:3]            // b = [2 3], len 2, cap 4, SHARES a's backing array
b[0] = 99             // mutates a too: a = [1 99 3 4 5]
b = append(b, 100)    // cap available -> writes into a[3]! a = [1 99 3 100 5]

// Safe copy when you must not alias:
c := make([]int, len(a))
copy(c, a)

// Full slice expression caps capacity to force a reallocation on next append:
d := a[1:3:3]         // len 2, cap 2 -> append now allocates, won't touch a

// Map gotchas:
m := map[string]int{}
v := m["missing"]      // returns zero value (0), NOT an error
v, ok := m["missing"]  // ok=false distinguishes absent from zero
// Maps are NOT safe for concurrent read+write -> use sync.RWMutex or sync.Map.
// You may NOT take the address of a map element (&m["k"] is illegal).

func process() (err error) {
    defer func() {
        if r := recover(); r != nil {        // recover only works inside a deferred func
            err = fmt.Errorf("recovered: %v", r)  // convert panic to error via named return
        }
    }()
    f, err := os.Open("data")
    if err != nil {
        return err
    }
    defer f.Close()                          // runs on every return path, LIFO

    i := 0
    defer fmt.Println("i at defer-time:", i)  // prints 0 (arg evaluated NOW)
    i = 42
    return nil
}

// BEFORE (leaks): slower backends block forever on send after the winner returns.
func fanoutBad(ctx context.Context, backends []Backend) Result {
    ch := make(chan Result)              // UNBUFFERED
    for _, b := range backends {
        go func(b Backend) { ch <- b.Call(ctx) }(b)  // blocks if no receiver
    }
    return <-ch                          // receives ONE; the others leak on send
}

// AFTER (no leak): buffered channel so every sender can complete, plus ctx cancel.
func fanoutGood(parent context.Context, backends []Backend) Result {
    ctx, cancel := context.WithCancel(parent)
    defer cancel()                       // signals the losers to stop work
    ch := make(chan Result, len(backends))  // buffer = N: no sender ever blocks
    for _, b := range backends {
        go func(b Backend) {
            select {
            case ch <- b.Call(ctx):
            case <-ctx.Done():           // abandon if we were cancelled
            }
        }(b)
    }
    return <-ch                          // first result wins; cancel() stops the rest
}

