package main

import (
    "context"
    "sync"
)

func merge(ctx context.Context, chans ...<-chan int) <-chan int {
    out := make(chan int)
    var wg sync.WaitGroup

    forward := func(c <-chan int) {
        defer wg.Done()
        for v := range c {                 // drains c until it is closed
            select {
            case out <- v:                 // forward downstream
            case <-ctx.Done():             // consumer gone / cancelled: exit, no leak
                return
            }
        }
    }

    wg.Add(len(chans))
    for _, c := range chans {
        go forward(c)
    }

    // Close out exactly once, after every forwarder has finished.
    go func() {
        wg.Wait()
        close(out)
    }()

    return out
}

package counter

import (
    "sync"
    "sync/atomic"
    "testing"
)

type Counter struct {
    n int64
}

func (c *Counter) Inc() {
    atomic.AddInt64(&c.n, 1)        // atomic read-modify-write: no mutex needed
}

func (c *Counter) Value() int64 {
    return atomic.LoadInt64(&c.n)   // atomic read pairs with the atomic writes
}

func TestCounterRaceFree(t *testing.T) {
    var c Counter
    var wg sync.WaitGroup
    const n = 1000
    wg.Add(n)
    for i := 0; i < n; i++ {
        go func() {
            defer wg.Done()
            c.Inc()
        }()
    }
    wg.Wait()
    if got := c.Value(); got != n {
        t.Fatalf("got %d, want %d", got, n)
    }
}
